import { useEffect, useState } from "react";
import schoolsDepartments from "../../data/schoolsDepartments";
import { useAuth } from "../../context/AuthContext";

import DeanLayout from "../../layouts/DeanLayout";

import {

  getFacultySubmissions,

  downloadFacultyPDF

} from "../../api/deanApi";

function DeanFacultyReview() {

    const { user } = useAuth();
    const [selectedDepartment, setSelectedDepartment] =
  useState("");
  
  const [submissions, setSubmissions] =
    useState([]);

  const [loading, setLoading] =
    useState(true);

  useEffect(() => {

    loadFacultySubmissions();

  }, []);

  const loadFacultySubmissions =
    async () => {

      try {

        const res =
          await getFacultySubmissions();

        setSubmissions(

          res.data.submissions || []

        );

      }

      catch (err) {

        console.error(err);

      }

      finally {

        setLoading(false);

      }

    };

  // ==========================
  // PDF DOWNLOAD
  // ==========================

  const handleDownload =
    async (submission) => {

      try {

        const response =
          await downloadFacultyPDF(
            submission._id
          );

        const url =
          window.URL.createObjectURL(
            new Blob([response.data])
          );

        const link =
          document.createElement("a");

        link.href = url;

        link.download =
          `${submission.submittedByName}_${submission.quarter}.pdf`;

        document.body.appendChild(link);

        link.click();

        link.remove();

      }

      catch (error) {

        console.error(error);

      }

    };

  // ==========================
  // GROUP BY DEPARTMENT
  // ==========================

  const groupedDepartments =
    submissions.reduce(

      (acc, submission) => {

        const dept =
          submission.department;

        if (!acc[dept]) {

          acc[dept] = [];

        }

        acc[dept].push(submission);

        return acc;

      },

      {}

    );
    // ==========================
// DEPARTMENTS OF DEAN SCHOOL
// ==========================

const departments =

  schoolsDepartments[user?.school] || [];

// ==========================
// FILTERED SUBMISSIONS
// ==========================

const filteredSubmissions =

  selectedDepartment

    ?

    submissions.filter(

      (submission) =>

        submission.department ===

        selectedDepartment

    )

    :

    [];

  return (

    <DeanLayout>

      <div
  style={{
    padding: "30px"
  }}
>

  <h1
    style={{
      marginBottom: "10px"
    }}
  >
    Faculty Reviews
  </h1>
 <div
  style={{
    marginBottom: "30px"
  }}
>

  <label
    style={{
      fontWeight: "600",
      display: "block",
      marginBottom: "10px"
    }}
  >

    Select Department

  </label>

  <select

    value={selectedDepartment}

    onChange={(e) =>

      setSelectedDepartment(

        e.target.value

      )

    }

    style={{

      width: "420px",

      padding: "12px",

      borderRadius: "8px",

      border: "1px solid #d1d5db"

    }}

  >

    <option value="">

      -- Select Department --

    </option>

    {

      departments.map(

        (department) => (

          <option

            key={department}

            value={department}

          >

            {department}

          </option>

        )

      )

    }

  </select>

</div>
  <p
    style={{
      color: "#6b7280",
      marginBottom: "30px"
    }}
  >
    Department-wise Faculty Submissions
    Approved by HOD
  </p>



</div>
    </DeanLayout>

  );

}
const thStyle = {

  padding: "12px",

  textAlign: "left",

  background: "#dbeafe"

};

const tdStyle = {

  padding: "12px",

  borderBottom:
    "1px solid #e5e7eb"

};
export default DeanFacultyReview;
